queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:genreID ?cg . ?child a :Genres ; p:genreID ?cg . ?l p:writerID ?pg . ?parent a :Writers ; p:writerID ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Writers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:genreID ?cg . ?child a :Genres ; p:genreID ?cg . ?l p:writerID ?pg . ?parent a :Writers ; p:writerID ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Writers } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?fullname ?name WHERE {
  ?writers_genres a :Writers_Genres .
  ?genres a :Genres .
  ?writers_genres p:hasGenres ?genres .
  ?writers a :Writers .
  ?writers_genres p:hasWriters ?writers .
  ?writers p:name ?fullname .
  ?genres p:name ?name .
} }
}
